export const resendConfirmSignUpFn = createServerFn({ method: "POST" })
  .inputValidator(confirmSignUpInputSchema.pick({ email: true }))
  .handler(async ({ data }): Promise<AuthResult> => {
    if (!isMockAuthEnabled()) {
      const { clientId } = getCognitoConfig();
      try {
        await getCognitoClient().send(
          new ResendConfirmationCodeCommand({
            ClientId: clientId,
            Username: data.email,
            SecretHash: secretHash(data.email),
          }),
        );
      } catch (err) {
        return { error: cognitoErrorMessage(err) };
      }
    }
    return { ok: true };
  });

export const submitForgotPasswordFn = createServerFn({ method: "POST" })
  .inputValidator(forgotPasswordInputSchema)
  .handler(async ({ data }): Promise<AuthResult> => {
    if (!isMockAuthEnabled()) {
      const { clientId } = getCognitoConfig();
      try {
        await getCognitoClient().send(
          new ForgotPasswordCommand({
            ClientId: clientId,
            Username: data.email,
            SecretHash: secretHash(data.email),
          }),
        );
      } catch (err) {
        if (err instanceof Error && err.name === "UserNotFoundException") {
          // Do not reveal whether an account exists; continue as success.
        } else {
          return { error: cognitoErrorMessage(err) };
        }
      }
    }

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const txSession = await useTransactionSession();
    await txSession.update({
      ...txSession.data,
      pendingResetEmail: data.email,
    });
    throw redirect({ to: "/reset-password", search: { sent: "1" } });
  });

export const submitResetPasswordFn = createServerFn({ method: "POST" })
  .inputValidator(resetPasswordInputSchema)
  .handler(async ({ data }): Promise<AuthResult> => {
    // In mock auth mode, we intentionally do not require/reset against a
    // pendingResetEmail session or Cognito code validation. This keeps local
    // UI/dev flows deterministic without external dependencies.
    if (!isMockAuthEnabled()) {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const txSession = await useTransactionSession();
      const email = txSession.data.pendingResetEmail;
      if (!email) {
        return { error: "Reset session expired. Please start over." };
      }

      const { clientId } = getCognitoConfig();
      try {
        await getCognitoClient().send(
          new ConfirmForgotPasswordCommand({
            ClientId: clientId,
            Username: email,
            ConfirmationCode: data.code,
            Password: data.newPassword,
            SecretHash: secretHash(email),
          }),
        );
        await txSession.update({
          ...txSession.data,
          pendingResetEmail: undefined,
        });
      } catch (err) {
        return { error: cognitoErrorMessage(err) };
      }
