  });

export const submitChallengeFn = createServerFn({ method: "POST" })
  .inputValidator(challengeInputSchema)
  .handler(async ({ data }): Promise<AuthResult> => {
    const txSession = await useTransactionSession();
    const oauthRequest = requireOauthRequest(txSession.data);
    const mockAuthEnabled = isMockAuthEnabled();

    if (!mockAuthEnabled) {
      const { clientId } = getCognitoConfig();
      const { challengeName, challengeSession, challengeUsername } =
        txSession.data;

      if (!challengeName || !challengeSession || !challengeUsername) {
        return { error: "No active challenge session." };
      }

      try {
        const challengeSecretHash = secretHash(challengeUsername);
        const challengeResponses: Record<string, string> = {
          USERNAME: challengeUsername,
          ...(challengeSecretHash ? { SECRET_HASH: challengeSecretHash } : {}),
        };
        if (challengeName === "NEW_PASSWORD_REQUIRED" && data.newPassword) {
          challengeResponses.NEW_PASSWORD = data.newPassword;
        } else if (
          (challengeName === "SMS_MFA" ||
            challengeName === "SOFTWARE_TOKEN_MFA") &&
          data.code
        ) {
          challengeResponses[
            challengeName === "SMS_MFA"
              ? "SMS_MFA_CODE"
              : "SOFTWARE_TOKEN_MFA_CODE"
          ] = data.code;
        } else {
          return { error: "Missing required challenge response." };
        }

        const result = await getCognitoClient().send(
          new RespondToAuthChallengeCommand({
            ClientId: clientId,
            ChallengeName: challengeName,
            Session: challengeSession,
            ChallengeResponses: challengeResponses,
          }),
        );

        // Handle nested challenges (e.g. NEW_PASSWORD_REQUIRED -> SMS_MFA)
        if (result.ChallengeName) {
          await txSession.update({
            ...txSession.data,
            challengeName: result.ChallengeName as typeof challengeName,
            challengeSession: result.Session,
            challengeUsername,
          });
          const to =
            result.ChallengeName === "NEW_PASSWORD_REQUIRED"
              ? "/force-change-password"
              : "/mfa-challenge";
          throw redirect({ to });
        }
      } catch (err) {
        rethrowIfRedirect(err);
        return { error: cognitoErrorMessage(err) };
      }

      await txSession.update({
        ...txSession.data,
        challengeName: undefined,
        challengeSession: undefined,
      });
      redirectThroughCognito(oauthRequest);
    } else {
      // Mock path
      if (
        txSession.data.challengeName === "NEW_PASSWORD_REQUIRED" &&
        !data.newPassword
      ) {
        return { error: "A new password is required." };
      }

      if (
        (txSession.data.challengeName === "SMS_MFA" ||
          txSession.data.challengeName === "SOFTWARE_TOKEN_MFA") &&
        !data.code
      ) {
        return { error: "A verification code is required." };
      }

      await txSession.update({
        ...txSession.data,
        challengeName: undefined,
        challengeSession: undefined,
      });

      const location = buildClientRedirect({
        code: `mock-${randomUUID()}`,
        redirect_uri: oauthRequest.redirectUri,
        state: oauthRequest.state,
      });
      throw redirect({ href: location });
    }
  });

export const beginLogoutFn = createServerFn({ method: "GET" })
  .inputValidator(logoutSearchSchema)
  .handler(async ({ data }) => {
    if (!isAllowedClientUri(data.client_id, data.logout_uri)) {
      throw redirect({
        to: "/error",
        search: { reason: "invalid_logout_uri" },
      });
    }

    const mockAuthEnabled = isMockAuthEnabled();
    const txSession = await useTransactionSession();
    if (mockAuthEnabled) {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const authSession = await useMockAuthSession();
      await authSession.clear();
    }
    await txSession.clear();

    const cognito = getCognitoConfig();
    if (!mockAuthEnabled && cognito.domain) {
      const logoutUrl = new URL("/logout", cognito.domain);
      logoutUrl.searchParams.set("client_id", data.client_id);
      logoutUrl.searchParams.set("logout_uri", data.logout_uri);
      throw redirect({ href: logoutUrl.toString() });
    }

    throw redirect({ href: data.logout_uri });
  });

export function preserveAuthorizeSearch(search: URLSearchParams) {
  const keys = [
    "client_id",
    "redirect_uri",
    "response_type",
    "scope",
    "state",
    "identity_provider",
  ];

  const preserved = new URLSearchParams();
  for (const key of keys) {
    const value = search.get(key);
    if (value) {
      preserved.set(key, value);
    }
  }
  return preserved;
}

