import { expect, test } from "@playwright/test";
import {
  allowedClientId,
  allowedLogoutUri,
  buildAuthorizeUrl,
} from "./helpers";

test("authorize rejects redirect_uri not in client allowlist", async ({
  page,
}) => {
  const url = buildAuthorizeUrl({
    clientId: allowedClientId,
    redirectUri: "https://evil.example.com/oauth",
  });

  await page.goto(url);

  await expect(page).toHaveURL(/\/error\?reason=invalid_redirect_uri/);
  await expect(
    page.getByText("The redirect URL is not allowed for this client."),
  ).toBeVisible();
});

test("logout rejects logout_uri not in client allowlist", async ({ page }) => {
  await page.goto(
    `/logout?client_id=${allowedClientId}&logout_uri=${encodeURIComponent("https://evil.example.com/logout")}`,
  );

  await expect(page).toHaveURL(/\/error\?reason=invalid_logout_uri/);
  await expect(
    page.getByText("The logout URL is not allowed for this client."),
  ).toBeVisible();
});

test("logout allows configured logout_uri", async ({ request }) => {
  const response = await request.get(
    `/logout?client_id=${allowedClientId}&logout_uri=${encodeURIComponent(allowedLogoutUri)}`,
    { maxRedirects: 0 },
  );

  expect(response.status()).toBe(307);
  expect(response.headers().location).toBe(allowedLogoutUri);
});

import { expect, test } from "@playwright/test";
import {
  authorizeUrl,
  mockClientRedirect,
  startSignIn,
  submitSignIn,
} from "./helpers";

test("authorize redirects to sign-in", async ({ page }) => {
  await page.goto(authorizeUrl);
  await expect(page).toHaveURL(/\/sign-in/);
  await expect(page.getByText("Welcome back")).toBeVisible();
});

test("normal sign-in redirects to client redirect_uri", async ({ page }) => {
  await mockClientRedirect(page);
  await startSignIn(page);
  await submitSignIn(page, "user@example.com");
  await expect(page).toHaveURL(/org\.anedot\.me\/oauth\?code=mock-/);
});

test("mfa email triggers MFA challenge screen", async ({ page }) => {
  await startSignIn(page);
  await submitSignIn(page, "mfa@example.com");
  await expect(page).toHaveURL(/\/mfa-challenge/);
  await expect(page.getByText("Verify code")).toBeVisible();
});

test("newpass email triggers force-change-password screen", async ({
  page,
}) => {
  await startSignIn(page);
  await submitSignIn(page, "newpass@example.com");
  await expect(page).toHaveURL(/\/force-change-password/);
  await expect(page.getByText("Set a new password")).toBeVisible();
});

test("unconfirmed email triggers confirm-sign-up screen", async ({ page }) => {
  await startSignIn(page);
  await submitSignIn(page, "unconfirmed@example.com");
  await expect(page).toHaveURL(/\/confirm-sign-up/);
  await expect(
    page.getByRole("heading", { name: /confirm account/i }),
  ).toBeVisible();
});

