import { orgApiScopedPath } from "./org-api-scoped-path";

describe("orgApiScopedPath", () => {
  it("adds tenant_id and omits vendor_id for org-only scope", () => {
    expect(orgApiScopedPath("/campaigns", { tenantId: 42 })).toBe(
      "/campaigns?tenant_id=42",
