import type { Tenant } from "@/types/bootstrap";
import { describe, expect, it } from "vitest";
import { pickSelectedTenantId } from "./user-session";

function makeTenant(id: number, updated_at: string): Tenant {
  return {
    id,
    tenant_type: "org",
    name: `Tenant ${id}`,
    org_id: `org-${id}`,
    vendor_id: null,
    created_at: updated_at,
    updated_at,
  };
}

describe("pickSelectedTenantId", () => {
  it("returns null when there are no tenants", () => {
    expect(pickSelectedTenantId([], null)).toBeNull();
    expect(pickSelectedTenantId([], 42)).toBeNull();
  });

  it("returns the stored id when it matches a tenant", () => {
    const tenants = [
      makeTenant(1, "2025-01-01T00:00:00Z"),
      makeTenant(2, "2025-02-01T00:00:00Z"),
    ];
    expect(pickSelectedTenantId(tenants, 2)).toBe(2);
    expect(pickSelectedTenantId(tenants, 1)).toBe(1);
  });

  it("falls back to the most-recent tenant when stored id is invalid", () => {
    const tenants = [
      makeTenant(1, "2025-01-01T00:00:00Z"),
      makeTenant(2, "2025-03-01T00:00:00Z"),
      makeTenant(3, "2025-02-01T00:00:00Z"),
