  "C2007CB8A163BF0598DA48361C55D39A69163FA8FD24CF5F" +
  "83655D23DCA3AD961C62F356208552BB9ED529077096966D" +
  "670C354E4ABC9804F1746C08CA18217C32905E462E36CE3B" +
  "E39E772C180E86039B2783A2EC07A28FB5C55DF06F4C52C9" +
  "DE2BCBF6955817183995497CEA956AE515D2261898FA0510" +
  "15728E5A8AACAA68FFFFFFFFFFFFFFFF";
const G_HEX = "2";
const INFO_BITS = "Caldera Derived Key";
const N_BIGINT = hexToBigInt(N_HEX);
const G_BIGINT = hexToBigInt(G_HEX);
// SRP multiplier k = H(padHex(N) || padHex(g)).
// Using toPaddedHex for both values keeps us aligned with Cognito helper behavior.
const K_BIGINT = hexToBigInt(
  hashHex(`${toPaddedHex(N_BIGINT)}${toPaddedHex(G_BIGINT)}`),
);

type CognitoAuthResult =
  | InitiateAuthCommandOutput
  | RespondToAuthChallengeCommandOutput;

export async function signInWithSrp(
  username: string,
  password: string,
): Promise<CognitoAuthResult> {
  const { clientId, userPoolId } = getCognitoConfig();
  const poolName = parsePoolName(userPoolId);
  const smallA = randomSmallAValue();
  const largeA = calculateLargeAValue(smallA);
  const signInSecretHash = secretHash(username);

  const initiateResponse = await getCognitoClient().send(
    new InitiateAuthCommand({
      AuthFlow: "USER_SRP_AUTH",
      AuthParameters: {
        USERNAME: username,
        SRP_A: toPaddedHex(largeA),
        ...(signInSecretHash ? { SECRET_HASH: signInSecretHash } : {}),
      },
      ClientId: clientId,
    }),
  );

  if (initiateResponse.ChallengeName !== "PASSWORD_VERIFIER") {
    return initiateResponse;
  }

  const challengeParameters = initiateResponse.ChallengeParameters;
  if (!challengeParameters) {
    throw new Error("Cognito SRP challenge parameters are missing.");
  }

  const srpBHex = challengeParameters.SRP_B;
  const saltHex = challengeParameters.SALT;
  const secretBlock = challengeParameters.SECRET_BLOCK;
  const userIdForSrp = challengeParameters.USER_ID_FOR_SRP ?? username;
  if (!srpBHex || !saltHex || !secretBlock) {
    throw new Error("Cognito SRP challenge parameters are incomplete.");
  }

  const timestamp = utcTimestamp();
  const signature = calculatePasswordClaimSignature({
    password,
    poolName,
    saltHex,
    secretBlock,
    largeA,
    smallA,
    srpBHex,
    timestamp,
    userIdForSrp,
  });
  const challengeSecretHash = secretHash(userIdForSrp);

  return getCognitoClient().send(
    new RespondToAuthChallengeCommand({
      ChallengeName: "PASSWORD_VERIFIER",
      ChallengeResponses: {
        USERNAME: userIdForSrp,
        PASSWORD_CLAIM_SECRET_BLOCK: secretBlock,
        PASSWORD_CLAIM_SIGNATURE: signature,
        TIMESTAMP: timestamp,
        ...(challengeSecretHash ? { SECRET_HASH: challengeSecretHash } : {}),
      },
      ClientId: clientId,
      Session: initiateResponse.Session,
    }),
  );
}

function parsePoolName(userPoolId: string): string {
  const [, poolName] = userPoolId.split("_");
  if (!poolName) {
    throw new Error("COGNITO_USER_POOL_ID is required for USER_SRP_AUTH.");
  }
  return poolName;
}

function calculatePasswordClaimSignature({
  password,
  poolName,
  saltHex,
  secretBlock,
  largeA,
  smallA,
  srpBHex,
  timestamp,
  userIdForSrp,
}: {
  password: string;
  poolName: string;
  saltHex: string;
  secretBlock: string;
  largeA: bigint;
  smallA: bigint;
  srpBHex: string;
  timestamp: string;
  userIdForSrp: string;
}): string {
  const srpBBigInt = hexToBigInt(srpBHex);
  if (srpBBigInt % N_BIGINT === 0n) {
    throw new Error("Invalid Cognito SRP_B challenge value.");
  }

  const userIdHash = hash(`${poolName}${userIdForSrp}:${password}`);
  const x = hexToBigInt(
    hashHex(`${toPaddedHex(hexToBigInt(saltHex))}${userIdHash}`),
  );
  const u = hexToBigInt(
    hashHex(`${toPaddedHex(largeA)}${toPaddedHex(srpBBigInt)}`),
  );
  if (u === 0n) {
    throw new Error("Cognito SRP generated an invalid u value.");
  }

  const gModPowX = modPow(G_BIGINT, x, N_BIGINT);
  const intValue2 = (srpBBigInt - K_BIGINT * gModPowX) % N_BIGINT;
  const base = ((intValue2 % N_BIGINT) + N_BIGINT) % N_BIGINT;
  const exponent = smallA + u * x;
  const sharedSecret = modPow(base, exponent, N_BIGINT);

  const hkdfKey = hkdf(
    Buffer.from(toPaddedHex(sharedSecret), "hex"),
    Buffer.from(toPaddedHex(u), "hex"),
  );

  const message = Buffer.concat([
    Buffer.from(poolName, "utf8"),
    Buffer.from(userIdForSrp, "utf8"),
    Buffer.from(secretBlock, "base64"),
    Buffer.from(timestamp, "utf8"),
  ]);
  return createHmac("sha256", hkdfKey).update(message).digest("base64");
}

function calculateLargeAValue(smallA: bigint): bigint {
  const largeA = modPow(G_BIGINT, smallA, N_BIGINT);
  if (largeA % N_BIGINT === 0n) {
    throw new Error("Cognito SRP generated an invalid public client value.");
  }
  return largeA;
}

function randomSmallAValue(): bigint {
  return hexToBigInt(randomBytes(128).toString("hex")) % N_BIGINT;
}

function hashHex(input: string): string {
  return hash(Buffer.from(input, "hex"));
}

function hash(input: Buffer | string): string {
  return createHash("sha256").update(input).digest("hex");
}

function toPaddedHex(value: bigint): string {
  const hex = value.toString(16);
  if (hex.length % 2 === 1) {
    return `0${hex}`;
  }
  const startsWithHighBit =
    hex.startsWith("8") ||
    hex.startsWith("9") ||
    hex.startsWith("a") ||
    hex.startsWith("b") ||
    hex.startsWith("c") ||
    hex.startsWith("d") ||
    hex.startsWith("e") ||
    hex.startsWith("f");
  return startsWithHighBit ? `00${hex}` : hex;
}

function hkdf(ikm: Buffer, salt: Buffer): Buffer {
  const prk = createHmac("sha256", salt).update(ikm).digest();
  return createHmac("sha256", prk)
    .update(Buffer.concat([Buffer.from(INFO_BITS, "utf8"), Buffer.from([1])]))
    .digest()
    .subarray(0, 16);
}

function hexToBigInt(hex: string): bigint {
  return BigInt(`0x${hex}`);
}

function modPow(base: bigint, exponent: bigint, modulus: bigint): bigint {
  if (modulus === 1n) {
    return 0n;
  }
  let result = 1n;
  let runningBase = base % modulus;
  let runningExponent = exponent;
  while (runningExponent > 0n) {
    if (runningExponent % 2n === 1n) {
      result = (result * runningBase) % modulus;
    }
    runningExponent >>= 1n;
    runningBase = (runningBase * runningBase) % modulus;
  }
  return result;
}

function utcTimestamp(): string {
  const now = new Date();
  const day = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][
    now.getUTCDay()
  ];
  const month = [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
    "Jul",
    "Aug",
    "Sep",
    "Oct",
    "Nov",
    "Dec",
  ][now.getUTCMonth()];

