import { useEffect } from "react";
import { TanStackDevtools } from "@tanstack/react-devtools";
import type { QueryClient } from "@tanstack/react-query";
import {
  createRootRouteWithContext,
  HeadContent,
  Outlet,
  Scripts,
} from "@tanstack/react-router";
import { TanStackRouterDevtoolsPanel } from "@tanstack/react-router-devtools";
import { Toaster } from "@workspace/ui";
import { RootError } from "../components/root-error";
import { RootNotFound } from "../components/root-not-found";
import { getUserSession } from "../server/user-session";
import appCss from "../styles.css?url";
import "@fontsource-variable/outfit";

type RouterContext = {
  queryClient: QueryClient;
};

type HydratedWindow = Window & {
  __HYDRATED__?: boolean;
};

export const Route = createRootRouteWithContext<RouterContext>()({
  errorComponent: RootError,
  notFoundComponent: RootNotFound,
  loader: async () => ({
    userSession: await getUserSession(),
  }),
  head: () => ({
    links: [
      {
        href: appCss,
        rel: "stylesheet",
      },
    ],
    meta: [
      {
        charSet: "utf-8",
      },
      {
        content: "width=device-width, initial-scale=1",
        name: "viewport",
      },
      {
        title: "Org Next",
      },
    ],
  }),
  shellComponent: RootDocument,
});

const enableTanstackDevtools = process.env.NODE_ENV === "development" && false;

function RootDocument() {
  useEffect(() => {
    (window as HydratedWindow).__HYDRATED__ = true;
  }, []);
  return (
    <html lang="en">
      <head>
        <HeadContent />
      </head>
      <body>
        <Outlet />
        <Toaster position="top-right" richColors />
        {enableTanstackDevtools && (
          <TanStackDevtools
            eventBusConfig={{
              // port is 1000 more than the dev port
              port: 4208,
            }}
            config={{
              position: "bottom-right",
            }}
            plugins={[
              {
                name: "Org Next TanStack Devtools",
                render: <TanStackRouterDevtoolsPanel />,
              },
            ]}
          />
        )}
        <Scripts />
      </body>
    </html>
  );
}

