  InitiateAuthCommand,
  type InitiateAuthCommandOutput,
  RespondToAuthChallengeCommand,
  type RespondToAuthChallengeCommandOutput,
} from "@aws-sdk/client-cognito-identity-provider";
import { getCognitoClient, secretHash } from "./cognito";
import { getCognitoConfig } from "./env";

export type CognitoAuthResult =
  | InitiateAuthCommandOutput
  | RespondToAuthChallengeCommandOutput;

export async function signInWithPassword(
  username: string,
  password: string,
): Promise<CognitoAuthResult> {
  const { clientId } = getCognitoConfig();
  const hash = secretHash(username);

  const response = await getCognitoClient().send(
    new InitiateAuthCommand({
      AuthFlow: "USER_AUTH",
      AuthParameters: {
        USERNAME: username,
        PREFERRED_CHALLENGE: "PASSWORD",
        PASSWORD: password,
        ...(hash ? { SECRET_HASH: hash } : {}),
