import { useEffect, useRef, useState } from "react";
import { AuthCard } from "@/components/auth-card";
import { AuthLayout } from "@/components/auth-layout";
import { AuthPageHeader } from "@/components/auth-page-header";
import { getAuthStatusFn } from "@/features/auth/server-functions";
import { createFileRoute } from "@tanstack/react-router";

type BootstrapState = "idle" | "pending" | "success" | "error";

export const Route = createFileRoute("/auth-status")({
  component: AuthStatusRoute,
  validateSearch: (search) => ({
    debug: search.debug === true || search.debug === "true",
    redirect_url:
      typeof search.redirect_url === "string" ? search.redirect_url : "",
    session_url:
      typeof search.session_url === "string" ? search.session_url : undefined,
    session_token:
      typeof search.session_token === "string"
        ? search.session_token
        : undefined,
  }),
  loader: ({ location }) => {
    const parsed = location.search as { debug?: boolean };
    if (parsed.debug) {
      return getAuthStatusFn();
    }
    return null;
  },
});

function useBootstrap(sessionUrl?: string, sessionToken?: string) {
  const needsBootstrap = !!(sessionUrl && sessionToken);
  const [state, setState] = useState<BootstrapState>(
    needsBootstrap ? "idle" : "success",
  );
  const [error, setError] = useState<string | null>(null);
  const started = useRef(false);

  useEffect(() => {
    if (!sessionUrl || !sessionToken) {
      setState("success");
      return;
    }

    if (started.current) return;
    started.current = true;

    setState("pending");

    fetch(sessionUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ token: sessionToken }),
    })
      .then((res) => {
        if (res.ok) {
          setState("success");
        } else {
          return res.text().then((text) => {
            setState("error");
            setError(`${res.status}: ${text}`);
          });
        }
      })
      .catch((err) => {
        setState("error");
        setError(err instanceof Error ? err.message : String(err));
      });
  }, [sessionUrl, sessionToken]);

  return { state, error };
}

function AuthStatusRoute() {
  const search = Route.useSearch();
  const status = Route.useLoaderData();
  const bootstrap = useBootstrap(search.session_url, search.session_token);
  const redirected = useRef(false);

  useEffect(() => {
    if (search.debug) return;
    if (redirected.current) return;
    if (bootstrap.state !== "success") return;
    if (!search.redirect_url) return;

    redirected.current = true;
    window.location.href = search.redirect_url;
  }, [search.debug, bootstrap.state, search.redirect_url]);

  if (!search.debug) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center">
        {bootstrap.state === "error" ? (
          <div className="text-center">
            <p className="mb-2 text-slate-500 text-sm">
              Something went wrong. Please try again.
            </p>
            {bootstrap.error ? (
              <p className="mb-4 max-w-md text-red-600 text-xs">
                {bootstrap.error}
              </p>
            ) : null}
            {search.redirect_url ? (
              <a
                href={search.redirect_url}
                className="inline-block rounded-lg bg-blue-600 px-6 py-2.5 font-medium text-sm text-white transition-colors hover:bg-blue-700"
              >
                Continue to app
              </a>
            ) : null}
          </div>
        ) : (
          <div className="text-center">
            <div className="mx-auto mb-4 h-8 w-8 animate-spin rounded-full border-[3px] border-slate-200 border-t-blue-600" />
            <p className="text-slate-500 text-sm">
              {bootstrap.state === "pending"
                ? "Getting your session ready..."
                : "Signing you in..."}
            </p>
          </div>
        )}
      </div>
    );
  }

  return (
    <AuthLayout>
      <div className="w-full max-w-[480px]">
        <AuthPageHeader
          title="Authentication Status"
          subtitle="Debug view — review session before redirect."
        />

        <AuthCard>
          {status ? (
            <dl className="mb-6 space-y-3 text-sm">
              <Row
                label="Authenticated"
                value={status.authenticated ? "Yes" : "No"}
              />
              <Row label="Sub" value={status.sub} />
              <Row label="Email" value={status.email} />
              <Row label="Access Token" value={status.accessTokenPreview} />
              <Row
                label="Refresh Token"
                value={status.hasRefreshToken ? "Present" : "None"}
              />
              <Row
                label="Expires In"
                value={
                  status.expiresIn > 0
                    ? `${Math.floor(status.expiresIn / 60)}m ${status.expiresIn % 60}s`
                    : "Expired"
                }
              />
              <Row
                label="Expires At"
                value={
                  status.expiresAt
                    ? new Date(status.expiresAt * 1000).toISOString()
                    : null
                }
              />
            </dl>
          ) : null}

          {search.session_url ? (
            <div className="mb-4 rounded-lg bg-slate-50 p-3">
              <p className="mb-1 font-medium text-slate-700 text-xs">
                Session Bootstrap
              </p>
              <p className="mb-2 break-all text-slate-600 text-xs">
                {search.session_url}
              </p>
              <BootstrapStatus state={bootstrap.state} error={bootstrap.error} />
            </div>
          ) : null}

          {search.redirect_url ? (
            <>
              <div className="mb-4 rounded-lg bg-slate-50 p-3">
                <p className="mb-1 font-medium text-slate-700 text-xs">
                  Redirect URL
                </p>
                <p className="break-all text-slate-600 text-xs">
                  {search.redirect_url}
                </p>
              </div>
              <button
                type="button"
                disabled={bootstrap.state !== "success"}
                onClick={() => {
                  window.location.href = search.redirect_url;
                }}
                className="flex w-full cursor-pointer items-center justify-center rounded-[10px] bg-blue-600 px-5 py-3 font-semibold text-[15px] text-white transition-colors duration-150 hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-50"
              >
                {bootstrap.state === "pending"
                  ? "Bootstrapping session..."
                  : "Continue to app"}
              </button>
            </>
          ) : (
            <p className="text-slate-500 text-sm">No redirect URL provided.</p>
          )}
        </AuthCard>
      </div>
    </AuthLayout>
  );
}

function BootstrapStatus({
  state,
  error,
}: { state: BootstrapState; error: string | null }) {
  switch (state) {
    case "idle":
      return <p className="text-slate-500 text-xs">Waiting to start...</p>;
    case "pending":
      return <p className="text-blue-600 text-xs">Bootstrapping session...</p>;
    case "success":
      return <p className="text-green-600 text-xs">Session established</p>;
    case "error":
      return (
        <p className="text-red-600 text-xs">
          Failed: {error ?? "Unknown error"}
        </p>
      );
  }
}

function Row({
  label,
  value,
}: { label: string; value: string | null | undefined }) {
  return (
    <div className="flex justify-between gap-4">
      <dt className="font-medium text-slate-500">{label}</dt>
      <dd className="text-right text-slate-800">{value ?? "—"}</dd>
    </div>
  );
}

