function useBootstrap(sessionUrl?: string, sessionToken?: string) {
  const needsBootstrap = !!(sessionUrl && sessionToken);
  const [state, setState] = useState<BootstrapState>(
    needsBootstrap ? "idle" : "success",
  );
  const [error, setError] = useState<string | null>(null);
  const started = useRef(false);

  useEffect(() => {
    if (!sessionUrl || !sessionToken) {
      setState("success");
      return;
    }

    if (started.current) return;
    started.current = true;

    setState("pending");

    fetch(sessionUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ token: sessionToken }),
    })
      .then((res) => {
        if (res.ok) {
          setState("success");
        } else {
          return res.text().then((text) => {
            setState("error");
            setError(`${res.status}: ${text}`);
