  signUpInputSchema,
} from "./contracts";
import { buildClientRedirect } from "./redirects";

type AuthResult = { error?: string; ok?: boolean };

export function rethrowIfRedirect(err: unknown): void {
  if (isRedirect(err)) throw err;
}

const cognitoFriendlyMessages: Record<string, string> = {
  NotAuthorizedException: "Incorrect username or password.",
  UserNotFoundException: "Incorrect username or password.",
  UserNotConfirmedException:
    "Your account has not been confirmed yet. Please check your email for a verification code.",
  PasswordResetRequiredException:
    "You need to reset your password before signing in.",
  CodeMismatchException:
    "The verification code you entered is incorrect. Please try again.",
  ExpiredCodeException:
    "Your verification code has expired. Please request a new one.",
  UsernameExistsException: "An account with this email already exists.",
  InvalidPasswordException:
    "Your password does not meet the requirements. Please choose a stronger password.",
  LimitExceededException:
    "Too many attempts. Please wait a moment and try again.",
  TooManyRequestsException:
    "Too many requests. Please wait a moment and try again.",
};

function requireOauthRequest(
  sessionData: Awaited<ReturnType<typeof useTransactionSession>>["data"],
) {
  const request = sessionData.oauthRequest;
  if (!request) {
    throw redirect({
      to: "/error",
      search: { reason: "missing_auth_context" },
    });
  }
  return request;
}

function cognitoAuthorizeUrl(search: Record<string, string>) {
  const cognito = getCognitoConfig();
  if (!cognito.domain) {
    return null;
  }

  const authorize = new URL("/oauth2/authorize", cognito.domain);
  for (const [key, value] of Object.entries(search)) {
    authorize.searchParams.set(key, value);
  }
  return authorize.toString();
}

async function setAuthCookie(
  authResult: AuthenticationResultType | undefined,
): Promise<void> {
  if (!authResult?.AccessToken || !authResult?.IdToken) return;

  const claims = decodeIdTokenClaims(authResult.IdToken);
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const session = await useAuthCookieSession();
  await session.update({
    sub: claims.sub,
    email: claims.email,
    emailVerified: claims.email_verified,
    givenName: claims.given_name,
    familyName: claims.family_name,
    phoneNumber: claims.phone_number,
    accessToken: authResult.AccessToken,
    refreshToken: authResult.RefreshToken,
    expiresAt: Math.floor(Date.now() / 1000) + (authResult.ExpiresIn ?? 3600),
  });
}

async function setMockAuthCookie(email: string): Promise<void> {
  // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
  const session = await useAuthCookieSession();
  await session.update({
    sub: `mock-${email}`,
    email,
    emailVerified: true,
    accessToken: `mock-access-${randomUUID()}`,
    expiresAt: Math.floor(Date.now() / 1000) + 3600,
  });
}

function redirectToClient(
  oauthRequest: OauthRequestState,
  claims: BootstrapClaims,
): never {
  const clientUrl = oauthRequest.sessionUrl
    ? oauthRequest.redirectUri
    : buildClientRedirect({
        code: `auth-${randomUUID()}`,
        redirect_uri: oauthRequest.redirectUri,
        state: oauthRequest.state,
      });

  throw redirect({
    to: "/auth-status",
    search: {
      debug: oauthRequest.debug === true,
      redirect_url: clientUrl,
      session_url: oauthRequest.sessionUrl,
      session_token: oauthRequest.sessionUrl
        ? signBootstrapJwt(
            claims,
            getBootstrapJwtSecret(),
            getAuthIssuerUrl(getRequestUrl({ xForwardedHost: true }).origin),
          )
        : undefined,
    },
  });
}


export function cognitoErrorMessage(err: unknown): string {
  if (err instanceof Error && err.name in cognitoFriendlyMessages) {
    return cognitoFriendlyMessages[err.name];
  }
  return "An unexpected error occurred. Please try again.";
}

export const beginAuthorizeFn = createServerFn({ method: "GET" })
  .inputValidator(authorizeSearchSchema)
  .handler(async ({ data }) => {
    if (!isAllowedClientUri(data.client_id, data.redirect_uri)) {
      throw redirect({
        to: "/error",
        search: { reason: "invalid_redirect_uri" },
      });
    }

    if (data.session_url && !isAllowedUri(data.session_url)) {
      throw redirect({
        to: "/error",
        search: { reason: "invalid_session_url" },
      });
    }

    // SSO: if the user already has a valid auth cookie, skip sign-in
    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const authCookie = await useAuthCookieSession();
    const cookieExpiresAt = authCookie.data.expiresAt ?? 0;
    if (authCookie.data.accessToken && cookieExpiresAt > Math.floor(Date.now() / 1000)) {
      const ssoRequest: OauthRequestState = {
        clientId: data.client_id,
        debug: data.debug,
        redirectUri: data.redirect_uri,
        responseType: data.response_type,
        scope: data.scope,
        sessionUrl: data.session_url,
        state: data.state,
      };
      const claims: BootstrapClaims = {
        sub: authCookie.data.sub ?? "",
        email: authCookie.data.email ?? "",
        email_verified: authCookie.data.emailVerified ?? false,
        given_name: authCookie.data.givenName,
        family_name: authCookie.data.familyName,
        phone_number: authCookie.data.phoneNumber,
