        clientId: data.client_id,
        debug: data.debug,
        identityProvider: data.identity_provider,
        redirectUri: data.redirect_uri,
        responseType: data.response_type,
        scope: data.scope,
        sessionUrl: data.session_url,
        state: data.state,
      },
    });

    if (data.identity_provider && !isMockAuthEnabled()) {
      const url = cognitoAuthorizeUrl({
        client_id: data.client_id,
        identity_provider: data.identity_provider,
        redirect_uri: getAuthCallbackUrl(),
        response_type: "code",
        scope: data.scope,
        state: data.state,
      });
      if (!url) {
        throw redirect({
          to: "/error",
