export const beginLogoutFn = createServerFn({ method: "GET" })
  .inputValidator(logoutSearchSchema)
  .handler(async ({ data }) => {
    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const authCookie = await useAuthCookieSession();

    if (!isMockAuthEnabled() && authCookie.data.accessToken) {
      try {
        const client = getCognitoClient();
        await client.send(
          new GlobalSignOutCommand({
            AccessToken: authCookie.data.accessToken,
          }),
        );
      } catch {
        // Best-effort: token may already be expired or revoked
      }
    }

    await authCookie.clear();

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const txSession = await useTransactionSession();
    await txSession.clear();

    if (isMockAuthEnabled()) {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const authSession = await useMockAuthSession();
      await authSession.clear();
    }

    if (data.redirect_url) {
      if (!isAllowedUri(data.redirect_url)) {
        throw redirect({
          to: "/error",
          search: { reason: "invalid_logout_uri" },
        });
      }
      throw redirect({ href: data.redirect_url });
    }

    return { signedOut: true };
  });

export const handleCallbackFn = createServerFn({ method: "GET" })
  .inputValidator(z.object({ code: z.string().min(1) }))
  .handler(async ({ data }) => {
    const txSession = await useTransactionSession();
    const oauthRequest = requireOauthRequest(txSession.data);

    const tokens = await exchangeCodeForTokens(
      data.code,
      getAuthCallbackUrl(),
    );

    const claims = decodeIdTokenClaims(tokens.id_token);
    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const session = await useAuthCookieSession();
    await session.update({
      sub: claims.sub,
      email: claims.email,
      emailVerified: claims.email_verified,
      givenName: claims.given_name,
      familyName: claims.family_name,
      phoneNumber: claims.phone_number,
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      expiresAt: Math.floor(Date.now() / 1000) + (tokens.expires_in ?? 3600),
    });

    redirectToClient(oauthRequest, claims);
  });

export const getAuthStatusFn = createServerFn({ method: "GET" }).handler(
  async () => {
    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const authCookie = await useAuthCookieSession();
    const now = Math.floor(Date.now() / 1000);
    const expiresAt = authCookie.data.expiresAt ?? 0;
    return {
      authenticated: Boolean(authCookie.data.accessToken),
      sub: authCookie.data.sub ?? null,
      email: authCookie.data.email ?? null,
      hasRefreshToken: Boolean(authCookie.data.refreshToken),
      expiresAt: expiresAt || null,
      expiresIn: expiresAt > now ? expiresAt - now : 0,
      accessTokenPreview: authCookie.data.accessToken
        ? `${authCookie.data.accessToken.slice(0, 20)}...`
        : null,
    };
  },
);

export function preserveAuthorizeSearch(search: URLSearchParams) {
  const keys = [
    "client_id",
    "redirect_uri",
    "response_type",
    "scope",
    "session_url",
    "state",
    "identity_provider",
  ];

  const preserved = new URLSearchParams();
  for (const key of keys) {
    const value = search.get(key);
    if (value) {
      preserved.set(key, value);
    }
  }
  return preserved;
}

