import { describe, expect, it } from "vitest";
import { decodeIdTokenClaims } from "./cognito-token";

describe("decodeIdTokenClaims", () => {
  function makeIdToken(payload: Record<string, unknown>): string {
    const header = btoa(JSON.stringify({ alg: "RS256", typ: "JWT" }));
    const body = btoa(JSON.stringify(payload));
    return `${header}.${body}.fake-signature`;
  }

  it("extracts sub, email, and email_verified from a valid id_token", () => {
    const token = makeIdToken({
      sub: "abc-123",
      email: "user@example.com",
      email_verified: true,
      iss: "https://cognito-idp.us-west-2.amazonaws.com/us-west-2_abc",
    });

    expect(decodeIdTokenClaims(token)).toEqual({
      sub: "abc-123",
      email: "user@example.com",
      email_verified: true,
    });
  });

  it("defaults email_verified to false when missing", () => {
    const token = makeIdToken({
      sub: "abc-123",
      email: "user@example.com",
    });

    expect(decodeIdTokenClaims(token)).toEqual({
      sub: "abc-123",
      email: "user@example.com",
      email_verified: false,
    });
  });

  it("throws on malformed token with wrong segment count", () => {
    expect(() => decodeIdTokenClaims("not-a-jwt")).toThrow(
      "Malformed id_token",
    );
  });
});

import { describe, expect, it } from "vitest";
import { signBootstrapJwt } from "./bootstrap-jwt";

describe("signBootstrapJwt", () => {
  const secret = "test-secret-at-least-32-characters-long";
  const issuer = "https://auth.anedot.com";
  const claims = { sub: "user-123", email: "user@example.com", email_verified: true };

  it("produces a three-segment JWT", () => {
    const jwt = signBootstrapJwt(claims, secret, issuer);
    expect(jwt.split(".")).toHaveLength(3);
  });

  it("includes the expected payload claims", () => {
    const jwt = signBootstrapJwt(claims, secret, issuer);
    const payload = JSON.parse(
      Buffer.from(jwt.split(".")[1], "base64url").toString(),
    );

    expect(payload.iss).toBe(issuer);
    expect(payload.aud).toBe("anedot-rails-api");
    expect(payload.sub).toBe("user-123");
    expect(payload.email).toBe("user@example.com");
    expect(payload.email_verified).toBe(true);
    expect(payload.token_use).toBe("session_bootstrap");
    expect(payload.ver).toBe(1);
    expect(payload.exp - payload.iat).toBe(60);
    expect(payload.jti).toBeDefined();
  });

  it("generates unique jti values", () => {
    const jwt1 = signBootstrapJwt(claims, secret, issuer);
    const jwt2 = signBootstrapJwt(claims, secret, issuer);
    const jti1 = JSON.parse(
      Buffer.from(jwt1.split(".")[1], "base64url").toString(),
    ).jti;
    const jti2 = JSON.parse(
      Buffer.from(jwt2.split(".")[1], "base64url").toString(),
    ).jti;
    expect(jti1).not.toBe(jti2);
  });
});

