describe("isAllowedUri", () => {
  it("allows a URI that appears in any client entry", () => {
    process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID = JSON.stringify({
      "client-a": ["https://app.anedot.com/oauth/callback"],
      "client-b": ["https://other.anedot.com/callback"],
