    process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID = JSON.stringify({
      "client-a": ["https://app.anedot.com/oauth/callback"],
    });

    expect(isAllowedUri("https://evil.example.com/hack")).toBe(false);
  });

  it("matches wildcard patterns across clients", () => {
    process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID = JSON.stringify({
      "client-a": ["https://*.anedot.com/*/callback"],
