    expect(isAllowedUri("https://qa1.anedot.com/auth/callback")).toBe(true);
    expect(isAllowedUri("https://evil.example.com/auth/callback")).toBe(false);
  });

  it("returns false when allowlist env is missing", () => {
    delete process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
    expect(isAllowedUri("https://app.anedot.com/callback")).toBe(false);
  });
});

