import { expect, test } from "@playwright/test";
import {
  authorizeUrl,
  mockClientRedirect,
  startSignIn,
  submitSignIn,
} from "./helpers";

test("authorize redirects to sign-in", async ({ page }) => {
  await page.goto(authorizeUrl);
  await expect(page).toHaveURL(/\/sign-in/);
  await expect(page.getByText("Welcome back")).toBeVisible();
});

test("normal sign-in redirects to client redirect_uri", async ({ page }) => {
  await mockClientRedirect(page);
  await startSignIn(page);
  await submitSignIn(page, "user@example.com");
  await expect(page).toHaveURL(/org\.anedot\.me\/oauth\?code=mock-/);
});

test("mfa email triggers MFA challenge screen", async ({ page }) => {
  await startSignIn(page);
  await submitSignIn(page, "mfa@example.com");
  await expect(page).toHaveURL(/\/mfa-challenge/);
  await expect(page.getByText("Verify code")).toBeVisible();
});

test("newpass email triggers force-change-password screen", async ({
  page,
}) => {
  await startSignIn(page);
  await submitSignIn(page, "newpass@example.com");
  await expect(page).toHaveURL(/\/force-change-password/);
  await expect(page.getByText("Set a new password")).toBeVisible();
});

test("unconfirmed email triggers confirm-sign-up screen", async ({ page }) => {
  await startSignIn(page);
  await submitSignIn(page, "unconfirmed@example.com");
  await expect(page).toHaveURL(/\/confirm-sign-up/);
  await expect(
    page.getByRole("heading", { name: /confirm account/i }),
  ).toBeVisible();
});

import { expect, type Locator, type Page } from "@playwright/test";

type AuthorizeQuery = {
  clientId?: string;
  redirectUri?: string;
  responseType?: string;
  scope?: string;
  state?: string;
};

type AllowedUrisByClientId = Record<string, string[]>;

const DEFAULT_CLIENT_ID = "local-client";
const FALLBACK_REDIRECT_URI = "https://org.anedot.me/oauth";
const FALLBACK_LOGOUT_URI = "https://org.anedot.me/logout";

function parseAllowedUrisByClientId(): AllowedUrisByClientId {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
  if (!raw) return {};

  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {};
    }
    return parsed as AllowedUrisByClientId;
  } catch {
    return {};
  }
}

function getAllowedUrisForClient(clientId: string) {
  const allUris = parseAllowedUrisByClientId();
  const uris = allUris[clientId];
  return Array.isArray(uris) ? uris : [];
}

function pickAllowedUri(
  clientId: string,
  preferredPath: string,
  fallback: string,
) {
  const uris = getAllowedUrisForClient(clientId);
  return uris.find((uri) => uri.includes(preferredPath)) ?? uris[0] ?? fallback;
}

export const allowedClientId = DEFAULT_CLIENT_ID;
export const allowedRedirectUri = pickAllowedUri(
  allowedClientId,
  "/oauth",
  FALLBACK_REDIRECT_URI,
);
export const allowedLogoutUri = pickAllowedUri(
  allowedClientId,
  "/logout",
  FALLBACK_LOGOUT_URI,
);

export function buildAuthorizeUrl(query: AuthorizeQuery = {}) {
  const search = new URLSearchParams({
    client_id: query.clientId ?? allowedClientId,
    redirect_uri: query.redirectUri ?? allowedRedirectUri,
    response_type: query.responseType ?? "code",
    scope: query.scope ?? "openid",
    state: query.state ?? "test-state-123",
  });
  return `/authorize?${search.toString()}`;
}

export const authorizeUrl = buildAuthorizeUrl();

export async function startSignIn(page: Page) {
  await page.goto(authorizeUrl);
  await expect(page).toHaveURL(/\/sign-in/);
  // Wait on a concrete UI element instead of `networkidle`: under `vite dev`,
  // HMR websockets and on-demand transforms keep the network busy, so
  // `networkidle` is stochastic. Assertions auto-retry to `expect.timeout`.
  await expect(page.getByLabel("Email")).toBeVisible();
}

export async function submitSignIn(
  page: Page,
  email: string,
  password = "password123",
) {
  await fillInput(page.getByLabel("Email"), email);
  await fillInput(page.getByLabel("Password"), password);
  await page.getByRole("button", { name: /sign in/i }).click();
}

export async function fillInput(input: Locator, value: string) {
  await input.click();
  await input.fill(value);

  if ((await input.inputValue()) !== value) {
    await input.fill("");
    await input.pressSequentially(value);
  }
}

export async function mockClientRedirect(page: Page) {
  const redirectOrigin = new URL(allowedRedirectUri).origin;
  const logoutOrigin = new URL(allowedLogoutUri).origin;

  await page.route(`${redirectOrigin}/**`, (route) =>
    route.fulfill({ status: 200, body: "OK" }),
  );
  if (logoutOrigin !== redirectOrigin) {
    await page.route(`${logoutOrigin}/**`, (route) =>
      route.fulfill({ status: 200, body: "OK" }),
    );
  }
}

import { expect, test } from "@playwright/test";
import { fillInput, mockClientRedirect, startSignIn } from "./helpers";

async function startSignUp(page: Parameters<typeof startSignIn>[0]) {
  await startSignIn(page);
  await page.getByRole("link", { name: /sign up/i }).click();
  await expect(page).toHaveURL(/\/sign-up/);
  await expect(page.getByLabel("Email address")).toBeVisible();
}

async function fillSignUpForm(
  page: Parameters<typeof startSignIn>[0],
  email: string,
  password = "Password123",
) {
  await fillInput(page.getByLabel("First name"), "Test");
  await fillInput(page.getByLabel("Last name"), "User");
  await fillInput(page.getByLabel("Email address"), email);
  await fillInput(page.getByLabel("Phone number"), "5555555555");
  await fillInput(page.getByLabel("Password", { exact: true }), password);
  await fillInput(page.getByLabel("Confirm password"), password);
}

test("sign-in page has sign-up link", async ({ page }) => {
  await startSignIn(page);
  await expect(page.getByRole("link", { name: /sign up/i })).toBeVisible();
});

test("sign-up page renders", async ({ page }) => {
  await startSignUp(page);
  await expect(page.getByText("Create your account")).toBeVisible();
});

test("sign-up redirects to confirm-sign-up", async ({ page }) => {
  await startSignUp(page);
  await fillSignUpForm(page, "newuser@example.com");
  await page.getByRole("button", { name: /create account/i }).click();
  await expect(page).toHaveURL(/\/confirm-sign-up/);
  await expect(
    page.getByRole("heading", { name: /confirm account/i }),
  ).toBeVisible();
});

test("confirm-sign-up completes and redirects to client", async ({ page }) => {
  await mockClientRedirect(page);
  await startSignUp(page);
  await fillSignUpForm(page, "newuser@example.com");
  await page.getByRole("button", { name: /create account/i }).click();
  await expect(page).toHaveURL(/\/confirm-sign-up/);
  await expect(page.getByLabel("Verification code")).toBeVisible();
  await fillInput(page.getByLabel("Verification code"), "123456");
  await page.getByRole("button", { name: /confirm account/i }).click();
  await expect(page).toHaveURL(/org\.anedot\.me\/oauth\?code=mock-/);
});

test("confirm-sign-up has resend code button", async ({ page }) => {
  await startSignUp(page);
  await fillSignUpForm(page, "newuser@example.com");
  await page.getByRole("button", { name: /create account/i }).click();
  await expect(page).toHaveURL(/\/confirm-sign-up/);
  const resendButton = page.getByRole("button", { name: /resend code/i });
  await expect(resendButton).toBeVisible();
  await resendButton.click();
  await expect(page.getByText("Verification code resent.")).toBeVisible();
});

test("sign-up submit is disabled until password meets requirements", async ({
  page,
}) => {
  await startSignUp(page);
  await fillInput(page.getByLabel("Email address"), "newuser@example.com");
  await fillInput(page.getByLabel("Password", { exact: true }), "weak");
  await fillInput(page.getByLabel("Confirm password"), "weak");
  await expect(
    page.getByRole("button", { name: /create account/i }),
  ).toBeDisabled();
  await fillInput(page.getByLabel("Password", { exact: true }), "Password123");
  await fillInput(page.getByLabel("Confirm password"), "Password123");
  await expect(
    page.getByRole("button", { name: /create account/i }),
  ).toBeEnabled();
});

