import { AuthCard } from "@/components/auth-card";
import { AuthLayout } from "@/components/auth-layout";
import { AuthPageHeader } from "@/components/auth-page-header";
import { createFileRoute } from "@tanstack/react-router";

const errorMessageMap: Record<string, string> = {
  invalid_logout_uri: "The logout URL is not allowed for this client.",
  invalid_redirect_uri: "The redirect URL is not allowed for this client.",
  invalid_session_url: "The session URL is not allowed for this client.",
  missing_auth_context:
    "Your auth session context expired. Start again from your app.",
  missing_authorize_request:
    "This page requires an authorize request from a client app.",
  missing_cognito_domain: "The auth service is not configured correctly.",
};

export const Route = createFileRoute("/error")({
  component: ErrorRoute,
  validateSearch: (search) => ({
    reason:
      typeof search.reason === "string" ? search.reason : "unexpected_error",
  }),
});

function ErrorRoute() {
  const search = Route.useSearch();
  const message =
    errorMessageMap[search.reason] ?? "Something went wrong. Please try again.";

  return (
    <AuthLayout>
      <div className="w-full max-w-[400px]">
        <AuthPageHeader
          title="Unable to continue"
          subtitle="There was a problem with your request."
        />

        <AuthCard>
          <p className="mb-5 text-slate-600 text-sm">{message}</p>
          <button
            type="button"
            onClick={() => window.history.back()}
            className="flex w-full cursor-pointer items-center justify-center rounded-[10px] bg-blue-600 px-5 py-3 font-semibold text-[15px] text-white transition-colors duration-150 hover:bg-blue-700"
          >
            Go back
          </button>
        </AuthCard>
      </div>
    </AuthLayout>
  );
}

