// buttons trigger native form submission, dropdowns no-op, etc. We can't rely
// on `waitUntil: "networkidle"` here because Vite's dev HMR websocket and
// devtools keep producing low-frequency traffic, so instead we wait for the
// app itself to signal that the client bundle has run.
async function waitForAppHydrated(page: Page): Promise<void> {
  await page.waitForFunction(
    () => (window as { __HYDRATED__?: boolean }).__HYDRATED__ === true,
  );
}

export const test = base.extend<{ mockServerRequest: MockClient }>({
  // One `MockClient` per test. Mock schemas travel per-request via the
