import { AuthLayout } from "@/components/auth-layout";
import { AuthPageHeader } from "@/components/auth-page-header";
import { logoutSearchSchema } from "@/features/auth/contracts";
import { beginLogoutFn } from "@/features/auth/server-functions";
import { createFileRoute } from "@tanstack/react-router";

export const Route = createFileRoute("/logout")({
  component: LogoutRoute,
  validateSearch: (search) => logoutSearchSchema.parse(search),
  loader: async ({ location }) => {
    const parsed = logoutSearchSchema.parse(location.search);
    return beginLogoutFn({ data: parsed });
  },
});

function LogoutRoute() {
  const search = Route.useSearch();

  return (
    <AuthLayout>
