import { afterEach, describe, expect, it } from "vitest";
import {
  buildOrgNextReturnUrl,
  getOrgNextOrigin,
  isAllowedOrgNextOrigin,
  normalizeOrgNextReturnTo,
} from "./org-next-app";

const originalAllowedOrigins = process.env.ORG_NEXT_ALLOWED_ORIGINS;

afterEach(() => {
  if (originalAllowedOrigins === undefined) {
    delete process.env.ORG_NEXT_ALLOWED_ORIGINS;
  } else {
    process.env.ORG_NEXT_ALLOWED_ORIGINS = originalAllowedOrigins;
  }
});

describe("org-next app config", () => {
  it("uses the first configured origin as the return origin", () => {
    process.env.ORG_NEXT_ALLOWED_ORIGINS =
      "http://localhost:3210,https://org-next.anedot.com";

    expect(getOrgNextOrigin()).toBe("http://localhost:3210");
    expect(isAllowedOrgNextOrigin("https://org-next.anedot.com")).toBe(true);
    expect(isAllowedOrgNextOrigin("https://evil.example.com")).toBe(false);
  });

  it("accepts relative return paths", () => {
    expect(normalizeOrgNextReturnTo("/campaigns/1?tab=pages")).toBe(
      "/campaigns/1?tab=pages",
    );
  });

  it("rejects absolute or protocol-relative return paths", () => {
    expect(normalizeOrgNextReturnTo("https://evil.example.com")).toBeNull();
    expect(normalizeOrgNextReturnTo("//evil.example.com")).toBeNull();
  });

  it("adds auth_state to the return URL", () => {
    expect(
      buildOrgNextReturnUrl({
        app: "org-next",
        origin: "http://localhost:3210",
        returnTo: "/campaigns?tab=pages",
        state: "state-123",
      }),
    ).toBe("http://localhost:3210/campaigns?tab=pages&auth_state=state-123");
  });
});

