import { test as base, type Page } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";

// Matches the flag `src/routes/__root.tsx` sets in its hydration `useEffect`.
// Clicking or filling before React has attached listeners makes submit
// buttons trigger native form submission, dropdowns no-op, etc. We can't rely
// on `waitUntil: "networkidle"` here because Vite's dev HMR websocket and
// devtools keep producing low-frequency traffic, so instead we wait for the
// app itself to signal that the client bundle has run.
async function waitForAppHydrated(page: Page): Promise<void> {
  await page.waitForFunction(
    () => (window as { __HYDRATED__?: boolean }).__HYDRATED__ === true,
  );
}

export const test = base.extend<{ mockServerRequest: MockClient }>({
  // One `MockClient` per test. Mock schemas travel per-request via the
  // `x-mock-request` context header, so each test is fully isolated — do not
  // share or hoist this instance across tests.
  //
  // IMPORTANT: never call `mockServerRequest.reset()` after `page.goto(...)`.
  // `reset()` clears every handler while the app is still issuing server
  // requests, which races with RMP header sync and produces flaky test
  // failures. To change a response after load, re-register the same
  // `reqSchema` (same RegExp reference) — `MockClient.addMock` keys by the
  // schema reference, so the new response atomically replaces the old one.
  mockServerRequest: async ({ context }, use) => {
    const mockClient = new MockClient();
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await use(mockClient);
  },
  page: async ({ page, baseURL, context }, use) => {
    const localOrigin = baseURL ? new URL(baseURL).origin : undefined;
    const isSpecialScheme = (url: string) =>
      url.startsWith("about:") ||
      url.startsWith("blob:") ||
      url.startsWith("data:");

    await context.route("**/*", async (route) => {
      const requestUrl = route.request().url();
      if (!localOrigin || isSpecialScheme(requestUrl)) {
        await route.continue();
        return;
      }

      const requestOrigin = new URL(requestUrl).origin;
      if (requestOrigin === localOrigin) {
        await route.continue();
        return;
      }

      await route.abort();
      throw new Error(
        `[Playwright] Blocked external browser request: ${route.request().method()} ${requestUrl}\n All requests to external APIs must flow through server functions`,
      );
    });

    // Wrap `page.goto` so every navigation waits for React hydration before
    // returning. This prevents a whole class of flakes where the test fires
    // `click`/`fill` against SSR HTML whose event handlers haven't been
    // attached yet (observed as submit buttons doing native GET submits and
    // dropdown triggers being no-ops).
    const originalGoto = page.goto.bind(page);
    page.goto = async (url, options) => {
      const response = await originalGoto(url, options);
      await waitForAppHydrated(page);
      return response;
    };

    await use(page);
    await context.unroute("**/*");
  },
});

export { expect } from "@playwright/test";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { defineConfig, devices } from "@playwright/test";
import dotenv from "dotenv";

const configDirectory = path.dirname(fileURLToPath(import.meta.url));
/** Resolved from the config file so discovery works when CWD is the repo root (e.g. VS Code, `playwright --config apps/org-next/...`). */
const testsRoot = path.join(configDirectory, "tests");
const testEnvPath = path.resolve(configDirectory, ".env.e2e");
dotenv.config({ path: testEnvPath, override: true });

const ciBaseUrl = "http://localhost:3210";
const localBaseUrl = "http://localhost:3210";
const baseUrl = process.env.CI ? ciBaseUrl : localBaseUrl;
const readinessUrl = `${baseUrl}/robots.txt`;

/**
 * Kill any zombie process holding the port before the webServer starts.
 * `reuseExistingServer: false` + Vite's `strictPort: true` makes a
 * leftover process from a crashed/Ctrl-C'd previous run a hard failure,
 * so we reclaim the port defensively. `|| true` keeps the chain healthy
 * when the port is already free.
 */
const killPortCommand = (port: number) =>
  `(lsof -ti :${port} | xargs kill -9 2>/dev/null || true)`;
const webServerEnv = Object.fromEntries(
  Object.entries(process.env).filter(
    (entry): entry is [string, string] => entry[1] !== undefined,
  ),
);

/**
 * See https://playwright.dev/docs/test-configuration.
 */
export default defineConfig({
  // Local dev uses the Vite server; cold starts and HMR can exceed a 5s budget.
  // Must be >= `expect.timeout` so a single assertion can't exhaust the whole
  // test budget.
  timeout: 20_000,
  testDir: testsRoot,
  fullyParallel: true,
  retries: process.env.CI ? 2 : 1,
  workers: process.env.CI ? 8 : 5,
  reporter: [
    [
      "html",
      {
        outputFolder: path.join(configDirectory, "playwright-report"),
        open: "always",
      },
    ],
  ],
  expect: {
    timeout: 10_000,
  },
  use: {
    baseURL: baseUrl,
    trace: "retain-on-failure",
    video: "retain-on-failure",
  },
  projects: [{ name: "chromium", use: { ...devices["Desktop Chrome"] } }],
  webServer: {
    command: `${killPortCommand(3210)} && ${
      process.env.CI
        ? "pnpm exec vite build --mode e2e && pnpm exec vite preview --port 3210"
        : "pnpm exec vite dev --port 3210 --mode e2e"
    }`,
    env: webServerEnv,
    url: readinessUrl,
    reuseExistingServer: false,
    stdout: "pipe",
    stderr: "pipe",
  },
});

