import { describe, expect, it } from "vitest";
import { authorizeSearchSchema, logoutSearchSchema } from "./contracts";

describe("authorizeSearchSchema", () => {
  it("accepts https redirect_uri values", () => {
    const result = authorizeSearchSchema.safeParse({
      client_id: "local-client",
      redirect_uri: "https://org.anedot.me/oauth",
      response_type: "code",
      scope: "openid email profile",
      state: "state-123",
    });

    expect(result.success).toBe(true);
  });

  it("rejects non-https redirect_uri values", () => {
    const result = authorizeSearchSchema.safeParse({
      client_id: "local-client",
      redirect_uri: "javascript:alert(1)",
      response_type: "code",
      scope: "openid email profile",
      state: "state-123",
    });

    expect(result.success).toBe(false);
  });
});

describe("logoutSearchSchema", () => {
  it("accepts empty params", () => {
    const result = logoutSearchSchema.safeParse({});
    expect(result.success).toBe(true);
  });

  it("accepts a valid https redirect_url", () => {
    const result = logoutSearchSchema.safeParse({
      redirect_url: "https://app.anedot.com/dashboard",
    });
    expect(result.success).toBe(true);
  });

  it("rejects non-https redirect_url values", () => {
    const result = logoutSearchSchema.safeParse({
      redirect_url: "data:text/plain,bye",
    });
    expect(result.success).toBe(false);
  });
});
