import { redirect } from "@tanstack/react-router";
import { describe, expect, it } from "vitest";
import { cognitoErrorMessage, rethrowIfRedirect } from "./server-functions";

describe("rethrowIfRedirect", () => {
  it("rethrows TanStack redirect objects", () => {
    const redirectError = redirect({ to: "/mfa-challenge" });

    try {
      rethrowIfRedirect(redirectError);
      expect.unreachable("Expected redirect to be rethrown.");
    } catch (err) {
      expect(err).toBe(redirectError);
    }
  });

  it("does not throw for non-redirect errors", () => {
    expect(() => rethrowIfRedirect(new Error("not a redirect"))).not.toThrow();
  });
});

describe("cognitoErrorMessage", () => {
  it("returns a friendly message for known Cognito errors", () => {
    const error = new Error("bad credentials");
    error.name = "NotAuthorizedException";

    expect(cognitoErrorMessage(error)).toBe(
      "Incorrect username or password.",
    );
  });

  it("returns a generic message for unknown errors", () => {
    const error = new Error("socket hang up");
    error.name = "NetworkingError";

    expect(cognitoErrorMessage(error)).toBe(
      "An unexpected error occurred. Please try again.",
    );
  });

  it("maps UserNotFoundException to the same message as NotAuthorizedException", () => {
    const error = new Error("User does not exist.");
    error.name = "UserNotFoundException";

    expect(cognitoErrorMessage(error)).toBe(
      "Incorrect username or password.",
    );
  });
});
import { expect, type Locator, type Page } from "@playwright/test";

type AuthorizeQuery = {
  clientId?: string;
  redirectUri?: string;
  responseType?: string;
  scope?: string;
  state?: string;
};

type AllowedUrisByClientId = Record<string, string[]>;

const DEFAULT_CLIENT_ID = "local-client";
const FALLBACK_REDIRECT_URI = "https://org.anedot.me/oauth";
const FALLBACK_LOGOUT_URI = "https://org.anedot.me/logout";

function parseAllowedUrisByClientId(): AllowedUrisByClientId {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
  if (!raw) return {};

  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {};
    }
    return parsed as AllowedUrisByClientId;
  } catch {
    return {};
  }
}

function getAllowedUrisForClient(clientId: string) {
  const allUris = parseAllowedUrisByClientId();
  const uris = allUris[clientId];
  return Array.isArray(uris) ? uris : [];
}

function pickAllowedUri(
  clientId: string,
  preferredPath: string,
  fallback: string,
) {
  const uris = getAllowedUrisForClient(clientId);
  return uris.find((uri) => uri.includes(preferredPath)) ?? uris[0] ?? fallback;
}

export const allowedClientId = DEFAULT_CLIENT_ID;
export const allowedRedirectUri = pickAllowedUri(
  allowedClientId,
  "/oauth",
  FALLBACK_REDIRECT_URI,
);
export const allowedLogoutUri = pickAllowedUri(
  allowedClientId,
  "/logout",
  FALLBACK_LOGOUT_URI,
);

export function buildAuthorizeUrl(query: AuthorizeQuery = {}) {
  const search = new URLSearchParams({
    client_id: query.clientId ?? allowedClientId,
    redirect_uri: query.redirectUri ?? allowedRedirectUri,
    response_type: query.responseType ?? "code",
    scope: query.scope ?? "openid",
    state: query.state ?? "test-state-123",
  });
  return `/authorize?${search.toString()}`;
}

export const authorizeUrl = buildAuthorizeUrl();

export async function startSignIn(page: Page) {
  await page.goto(authorizeUrl);
  await expect(page).toHaveURL(/\/sign-in/);
  // Wait on a concrete UI element instead of `networkidle`: under `vite dev`,
  // HMR websockets and on-demand transforms keep the network busy, so
  // `networkidle` is stochastic. Assertions auto-retry to `expect.timeout`.
  await expect(page.getByLabel("Email")).toBeVisible();
}

export async function submitSignIn(
  page: Page,
  email: string,
  password = "password123",
) {
  await fillInput(page.getByLabel("Email"), email);
  await fillInput(page.getByLabel("Password"), password);
  await page.getByRole("button", { name: /sign in/i }).click();
}

export async function fillInput(input: Locator, value: string) {
  await input.click();
  await input.fill(value);

  if ((await input.inputValue()) !== value) {
    await input.fill("");
    await input.pressSequentially(value);
  }
}

export async function mockClientRedirect(page: Page) {
  const redirectOrigin = new URL(allowedRedirectUri).origin;
  const logoutOrigin = new URL(allowedLogoutUri).origin;

  await page.route(`${redirectOrigin}/**`, (route) =>
    route.fulfill({ status: 200, body: "OK" }),
  );
  if (logoutOrigin !== redirectOrigin) {
    await page.route(`${logoutOrigin}/**`, (route) =>
      route.fulfill({ status: 200, body: "OK" }),
    );
  }
}

