  } catch {
    return null;
  }
}

function isWildcardPattern(uri: string): boolean {
  return uri.includes("*");
}

function wildcardToRegExp(pattern: string): RegExp | null {
  if (!pattern.startsWith("https://")) return null;

  const placeholder = "\0WILD\0";
  const withPlaceholders = pattern.replace(/\*/g, placeholder);
  const escaped = withPlaceholders.replace(/[.+?^${}()|[\]\\]/g, "\\$&");
  const withWildcard = escaped.replaceAll(placeholder, ".+");
  return new RegExp(`^${withWildcard}$`);
}

function parseJsonObject(raw: string): Record<string, unknown> | null {
  const tryParseObject = (value: string): Record<string, unknown> | null => {
    const parsed = JSON.parse(value);
