  }
  return null;
}

function previewRawValue(raw: string): string {
  const maxLength = 500;
  if (raw.length <= maxLength) {
    return raw;
  }
  return `${raw.slice(0, maxLength)}...`;
}

function parseAllowedUrisByClientId(): ClientUriAllowlist {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
  if (!raw) {
    return new Map();
  }

  const parsed = parseJsonObject(raw);
  if (!parsed) {
    return new Map();
  }

  const allowlist: ClientUriAllowlist = new Map();
  for (const [clientId, uris] of Object.entries(parsed)) {
    if (!Array.isArray(uris)) {
      continue;
    }
    const exact = new Set<string>();
