type ClientUriAllowlist = Map<
  string,
  { exact: Set<string>; patterns: RegExp[] }
>;
type ClientUriCheckFailureReason =
  | "invalid_requested_uri"
  | "missing_allowlist_env"
  | "invalid_allowlist_json"
  | "missing_client_entry"
  | "no_allowed_uris_for_client"
  | "uri_not_in_allowlist";

export type ClientUriCheckDebugInfo = {
  allowedUrisForClient: string[];
  clientId: string;
  clientIdMatched: boolean;
  failureReason: ClientUriCheckFailureReason | null;
  isAllowed: boolean;
  normalizedRequestUri: string | null;
  parsedClientIds: string[];
  rawAllowlistEnvLength: number;
  rawAllowlistEnvPresent: boolean;
  rawAllowlistEnvPreview: string | null;
  requestUri: string;
  requestUriMatched: boolean;
};

function normalizeUri(uri: string): string | null {
  try {
    const parsed = new URL(uri);
    if (parsed.protocol !== "https:") {
      return null;
    }
    parsed.hash = "";
    return parsed.toString();
  } catch {
    return null;
  }
}

function isWildcardPattern(uri: string): boolean {
  return uri.includes("*");
}

function wildcardToRegExp(pattern: string): RegExp | null {
  if (!pattern.startsWith("https://")) return null;

  const placeholder = "\0WILD\0";
  const withPlaceholders = pattern.replace(/\*/g, placeholder);
  const escaped = withPlaceholders.replace(/[.+?^${}()|[\]\\]/g, "\\$&");
  const withWildcard = escaped.replaceAll(placeholder, ".+");
  return new RegExp(`^${withWildcard}$`);
}

function parseJsonObject(raw: string): Record<string, unknown> | null {
  const tryParseObject = (value: string): Record<string, unknown> | null => {
    const parsed = JSON.parse(value);
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>;
    }

    // Cloudflare dev vars may deliver escaped JSON strings.
    if (typeof parsed === "string") {
      const reparsed = JSON.parse(parsed);
      if (
        reparsed &&
        typeof reparsed === "object" &&
        !Array.isArray(reparsed)
      ) {
        return reparsed as Record<string, unknown>;
      }
    }
    return null;
  };

  try {
    const parsed = tryParseObject(raw);
    if (parsed) {
      return parsed;
    }
  } catch {
    // Try additional formats below.
  }

  // Some secret managers store shell-wrapped JSON including the outer single
  // quotes, e.g. '{"client":["https://example.com/callback"]}'.
  try {
    const trimmed = raw.trim();
    if (trimmed.startsWith("'") && trimmed.endsWith("'")) {
      const unwrapped = trimmed.slice(1, -1);
      const parsed = tryParseObject(unwrapped);
      if (parsed) {
        return parsed;
      }
    }
  } catch {
    // Try additional formats below.
  }

  // Wrangler can pass escaped JSON without wrapping quotes: {\"k\":\"v\"}
  try {
    const normalized = raw.replace(/\\"/g, '"');
    const parsed = tryParseObject(normalized);
    if (parsed) {
      return parsed;
    }
  } catch {
    // Ignore malformed JSON.
  }
  return null;
}

function previewRawValue(raw: string): string {
  const maxLength = 500;
  if (raw.length <= maxLength) {
    return raw;
  }
  return `${raw.slice(0, maxLength)}...`;
}

function parseAllowedUrisByClientId(): ClientUriAllowlist {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
  if (!raw) {
    return new Map();
  }

  const parsed = parseJsonObject(raw);
  if (!parsed) {
    return new Map();
  }

  const allowlist: ClientUriAllowlist = new Map();
  for (const [clientId, uris] of Object.entries(parsed)) {
    if (!Array.isArray(uris)) {
      continue;
    }
    const exact = new Set<string>();
    const patterns: RegExp[] = [];
    for (const uri of uris) {
      if (typeof uri !== "string") {
        continue;
      }
      if (isWildcardPattern(uri)) {
        const re = wildcardToRegExp(uri);
        if (re) patterns.push(re);
      } else {
        const normalized = normalizeUri(uri);
        if (normalized) exact.add(normalized);
      }
    }
    allowlist.set(clientId, { exact, patterns });
  }
  return allowlist;
}

export function isAllowedClientUri(clientId: string, uri: string) {
  return getClientUriCheckDebugInfo(clientId, uri).isAllowed;
}

export function isAllowedUri(uri: string): boolean {
  const normalized = normalizeUri(uri);
  if (!normalized) return false;

  const allowlist = parseAllowedUrisByClientId();
  for (const entry of allowlist.values()) {
    if (entry.exact.has(normalized)) return true;
    if (entry.patterns.some((re) => re.test(normalized))) return true;
  }
  return false;
}

export function getClientUriCheckDebugInfo(
  clientId: string,
  uri: string,
): ClientUriCheckDebugInfo {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
import { getOrgNextAllowedOrigins } from "./env";
import type { OauthRequestState } from "./session";

export const ORG_NEXT_APP_ID = "org-next";

export type OrgNextOauthRequest = OauthRequestState & {
  app: typeof ORG_NEXT_APP_ID;
  origin: string;
  returnTo: string;
};

export function isOrgNextOauthRequest(
  request: OauthRequestState,
): request is OrgNextOauthRequest {
  return request.app === ORG_NEXT_APP_ID;
}

export function getOrgNextOrigin(): string | null {
  return getOrgNextAllowedOrigins()[0] ?? null;
}

export function isAllowedOrgNextOrigin(origin: string): boolean {
  return getOrgNextAllowedOrigins().includes(origin);
}

export function normalizeOrgNextReturnTo(value: string): string | null {
  if (!value.startsWith("/") || value.startsWith("//")) {
    return null;
  }

  try {
    const parsed = new URL(value, "http://org-next.local");
    if (parsed.origin !== "http://org-next.local") {
      return null;
    }
    return `${parsed.pathname}${parsed.search}${parsed.hash}`;
  } catch {
    return null;
  }
}

export function buildOrgNextReturnUrl(request: OrgNextOauthRequest): string {
  const url = new URL(request.returnTo, request.origin);
  url.searchParams.set("auth_state", request.state);
  return url.toString();
}

