export function getSessionSecret() {
  const secret = process.env.AUTH_SESSION_SECRET?.trim();

  if (!secret) {
    throw new Error(
      "Missing AUTH_SESSION_SECRET. Set a strong secret (at least 32 characters).",
    );
  }

  if (secret === "dev-only-session-secret-change-me") {
    throw new Error(
      "Insecure AUTH_SESSION_SECRET value detected. Generate and set a unique secret.",
    );
  }

  if (secret.length < 32) {
    throw new Error("AUTH_SESSION_SECRET must be at least 32 characters long.");
  }

  return secret;
}

export function getCognitoConfig() {
  return {
    clientId: process.env.COGNITO_CLIENT_ID ?? "",
    clientSecret: process.env.COGNITO_CLIENT_SECRET ?? "",
    domain: process.env.COGNITO_DOMAIN ?? "",
    region: process.env.COGNITO_REGION ?? "us-west-2",
    userPoolId: process.env.COGNITO_USER_POOL_ID ?? "",
  };
}

export function getAuthCallbackUrl(): string {
  const url = process.env.AUTH_CALLBACK_URL?.trim();
  if (!url) {
    throw new Error(
      "Missing AUTH_CALLBACK_URL. Set the auth app's own OAuth callback URL (e.g. https://auth.anedot.com/callback).",
    );
  }
  return url;
}

export function getAuthCookieDomain(): string | undefined {
  const domain = process.env.AUTH_COOKIE_DOMAIN?.trim();
  return domain || undefined;
}

export function getAuthCookieSecret(): string {
  const secret = process.env.AUTH_COOKIE_SECRET?.trim();
  if (secret && secret.length >= 32) {
    return secret;
  }
  return getSessionSecret();
}

export function getBootstrapJwtSecret(): string {
  const secret = process.env.AUTH_BOOTSTRAP_JWT_SECRET?.trim();
  if (secret && secret.length >= 32) {
    return secret;
  }
  return getSessionSecret();
}

export function getAuthIssuerUrl(requestOrigin?: string): string {
  if (requestOrigin) {
    return requestOrigin;
  }
  return process.env.AUTH_ISSUER_URL?.trim() ?? "https://auth.anedot.com";
}

export function getOrgNextSessionSecret(): string {
  const secret = process.env.ORG_NEXT_SESSION_SECRET?.trim();

  if (!secret) {
    throw new Error(
      "Missing ORG_NEXT_SESSION_SECRET. Set it to the org-next SESSION_SECRET value.",
    );
  }

  if (secret.length < 32) {
    throw new Error("ORG_NEXT_SESSION_SECRET must be at least 32 characters.");
  }

  return secret;
}

export function getOrgNextCookieDomain(): string | undefined {
  const domain = process.env.ORG_NEXT_COOKIE_DOMAIN?.trim();
  return domain || undefined;
}

export function getOrgNextAllowedOrigins(): string[] {
  const raw = process.env.ORG_NEXT_ALLOWED_ORIGINS?.trim();
  if (!raw) {
    return [];
  }

  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      return parsed
        .filter((origin): origin is string => typeof origin === "string")
        .map((origin) => origin.trim())
        .filter(Boolean);
    }
  } catch {
    // Fall through to comma-separated parsing.
  }

  return raw
    .split(",")
    .map((origin) => origin.trim())
    .filter(Boolean);
}

  it("throws when AUTH_CALLBACK_URL is missing", () => {
