    expect(() => getAuthCallbackUrl()).toThrow("Missing AUTH_CALLBACK_URL");
  });
});

describe("getAuthCookieDomain", () => {
  it("returns the configured cookie domain", () => {
    process.env.AUTH_COOKIE_DOMAIN = ".anedot.com";
    expect(getAuthCookieDomain()).toBe(".anedot.com");
  });

  it("returns undefined when AUTH_COOKIE_DOMAIN is missing", () => {
    delete process.env.AUTH_COOKIE_DOMAIN;
    expect(getAuthCookieDomain()).toBeUndefined();
  });
});

describe("getAuthCookieSecret", () => {
  it("returns AUTH_COOKIE_SECRET when set and long enough", () => {
    process.env.AUTH_COOKIE_SECRET = "a".repeat(32);
    expect(getAuthCookieSecret()).toBe("a".repeat(32));
  });

  it("falls back to session secret when AUTH_COOKIE_SECRET is too short", () => {
    process.env.AUTH_COOKIE_SECRET = "short";
    process.env.AUTH_SESSION_SECRET = "b".repeat(32);
    expect(getAuthCookieSecret()).toBe("b".repeat(32));
  });

  it("falls back to session secret when AUTH_COOKIE_SECRET is unset", () => {
    delete process.env.AUTH_COOKIE_SECRET;
    process.env.AUTH_SESSION_SECRET = "c".repeat(32);
    expect(getAuthCookieSecret()).toBe("c".repeat(32));
  });
});

describe("org-next configuration", () => {
  it("returns comma-separated allowed origins", () => {
    process.env.ORG_NEXT_ALLOWED_ORIGINS =
      "http://localhost:3210,https://org-next.anedot.com";

    expect(getOrgNextAllowedOrigins()).toEqual([
      "http://localhost:3210",
      "https://org-next.anedot.com",
    ]);
  });

  it("returns JSON allowed origins", () => {
    process.env.ORG_NEXT_ALLOWED_ORIGINS = JSON.stringify([
      "http://localhost:3210",
    ]);

    expect(getOrgNextAllowedOrigins()).toEqual(["http://localhost:3210"]);
  });

  it("returns optional org-next cookie domain", () => {
    delete process.env.ORG_NEXT_COOKIE_DOMAIN;
    expect(getOrgNextCookieDomain()).toBeUndefined();

    process.env.ORG_NEXT_COOKIE_DOMAIN = ".anedot.com";
    expect(getOrgNextCookieDomain()).toBe(".anedot.com");
  });

  it("requires a strong org-next session secret", () => {
    delete process.env.ORG_NEXT_SESSION_SECRET;
    expect(() => getOrgNextSessionSecret()).toThrow(
      "Missing ORG_NEXT_SESSION_SECRET",
    );

    process.env.ORG_NEXT_SESSION_SECRET = "short";
    expect(() => getOrgNextSessionSecret()).toThrow(
      "ORG_NEXT_SESSION_SECRET must be at least 32 characters.",
    );

    process.env.ORG_NEXT_SESSION_SECRET = "d".repeat(32);
    expect(getOrgNextSessionSecret()).toBe("d".repeat(32));
  });
});

