export const beginLogoutFn = createServerFn({ method: "GET" })
  .inputValidator(logoutSearchSchema)
  .handler(async ({ data }) => {
    if ("app" in data && data.app === "org-next") {
      const origin = getOrgNextOrigin();
      const returnTo = normalizeOrgNextReturnTo(data.return_to);

      if (!origin || !returnTo) {
        throw redirect({
          to: "/error",
          search: { reason: "invalid_logout_uri" },
        });
      }

      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const orgNextAuthToken = await useOrgNextAuthTokenSession();

      if (!isMockAuthEnabled() && orgNextAuthToken.data.authToken) {
        try {
          const client = getCognitoClient();
          await client.send(
            new GlobalSignOutCommand({
              AccessToken: orgNextAuthToken.data.authToken,
            }),
          );
        } catch {
          // Best-effort: token may already be expired or revoked.
        }
      }

      await clearOrgNextTokenCookies();

      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const authCookie = await useAuthCookieSession();
      await authCookie.clear();

      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const txSession = await useTransactionSession();
      await txSession.clear();

      if (isMockAuthEnabled()) {
        // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
        const authSession = await useMockAuthSession();
        await authSession.clear();
      }

      throw redirect({ href: new URL(returnTo, origin).toString() });
    }

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const authCookie = await useAuthCookieSession();

    if (!isMockAuthEnabled() && authCookie.data.accessToken) {
      try {
        const client = getCognitoClient();
        await client.send(
          new GlobalSignOutCommand({
            AccessToken: authCookie.data.accessToken,
          }),
        );
      } catch {
        // Best-effort: token may already be expired or revoked
      }
    }

    await authCookie.clear();

    // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
    const txSession = await useTransactionSession();
    await txSession.clear();

    if (isMockAuthEnabled()) {
      // biome-ignore lint/correctness/useHookAtTopLevel: server function, not a React component
      const authSession = await useMockAuthSession();
      await authSession.clear();
    }

    const externalData = data as { redirect_url?: string };
    if (externalData.redirect_url) {
      if (!isAllowedUri(externalData.redirect_url)) {
        throw redirect({
          to: "/error",
          search: { reason: "invalid_logout_uri" },
        });
      }
      throw redirect({ href: externalData.redirect_url });
    }

    return { signedOut: true };
  });

