import { AuthCard } from "@/components/auth-card";
import { AuthLayout } from "@/components/auth-layout";
import { AuthPageHeader } from "@/components/auth-page-header";
import { logoutSearchSchema } from "@/features/auth/contracts";
import { beginLogoutFn } from "@/features/auth/server-functions";
import { createFileRoute } from "@tanstack/react-router";

export const Route = createFileRoute("/logout")({
  component: LogoutRoute,
  validateSearch: (search) => logoutSearchSchema.parse(search),
  loader: async ({ location }) => {
    const parsed = logoutSearchSchema.parse(location.search);
    return beginLogoutFn({ data: parsed });
  },
});

function LogoutRoute() {
  const search = Route.useSearch();
  const redirectUrl = "redirect_url" in search ? search.redirect_url : undefined;

  return (
    <AuthLayout>
      <div className="w-full max-w-[480px]">
        <AuthPageHeader
          title="Signed out"
          subtitle="You have been signed out successfully."
        />

        <AuthCard>
          {redirectUrl ? (
            <a
              href={redirectUrl}
              className="flex w-full items-center justify-center rounded-[10px] bg-blue-600 px-5 py-3 font-semibold text-[15px] text-white transition-colors duration-150 hover:bg-blue-700"
            >
              Return to app
            </a>
          ) : (
            <p className="text-center text-slate-500 text-sm">
              You may close this window.
            </p>
          )}
        </AuthCard>
      </div>
    </AuthLayout>
  );
}
