import { useEffect } from "react";
import { TanStackDevtools } from "@tanstack/react-devtools";
import type { QueryClient } from "@tanstack/react-query";
import {
  createRootRouteWithContext,
  HeadContent,
  Outlet,
  Scripts,
} from "@tanstack/react-router";
import { TanStackRouterDevtoolsPanel } from "@tanstack/react-router-devtools";
import { Toaster } from "@workspace/ui";
import { RootError } from "../components/root-error";
import { RootNotFound } from "../components/root-not-found";
import { getUserSession } from "../server/user-session";
import { verifyAuthReturn } from "./-auth";
import appCss from "../styles.css?url";
import "@fontsource-variable/outfit";

type RouterContext = {
  queryClient: QueryClient;
};

type HydratedWindow = Window & {
  __HYDRATED__?: boolean;
};

export const Route = createRootRouteWithContext<RouterContext>()({
  errorComponent: RootError,
  notFoundComponent: RootNotFound,
  loader: async ({ location }) => {
    await verifyAuthReturn({ data: { href: location.href } });
    return {
      userSession: await getUserSession(),
    };
  },
  head: () => ({
    links: [
      {
        href: appCss,
        rel: "stylesheet",
      },
    ],
    meta: [
      {
        charSet: "utf-8",
      },
      {
        content: "width=device-width, initial-scale=1",
        name: "viewport",
      },
      {
        title: "Org Next",
      },
    ],
  }),
  shellComponent: RootDocument,
});

const enableTanstackDevtools = process.env.NODE_ENV === "development" && false;

function RootDocument() {
  useEffect(() => {
    (window as HydratedWindow).__HYDRATED__ = true;
  }, []);
  return (
    <html lang="en">
      <head>
        <HeadContent />
      </head>
      <body>
        <Outlet />
        <Toaster position="top-right" richColors />
        {enableTanstackDevtools && (
          <TanStackDevtools
            eventBusConfig={{
              // port is 1000 more than the dev port
              port: 4208,
            }}
            config={{
              position: "bottom-right",
            }}
            plugins={[
              {
                name: "Org Next TanStack Devtools",
                render: <TanStackRouterDevtoolsPanel />,
              },
            ]}
          />
        )}
        <Scripts />
      </body>
    </html>
  );
}
import { useState } from "react";
import { MarketingCarousel } from "@/components/marketing-carousel";
import { createFileRoute } from "@tanstack/react-router";
import { AnedotTypemarkIcon, Button } from "@workspace/ui";
import { Loader2 } from "lucide-react";
import { initiateLogin, redirectIfAuthenticated } from "./-auth";

export const Route = createFileRoute("/login")({
  loader: () => redirectIfAuthenticated(),
  validateSearch: (
    search: Record<string, unknown>,
  ): { error?: string; logged_out?: string; return_to?: string } => ({
    error: typeof search.error === "string" ? search.error : undefined,
    logged_out:
      typeof search.logged_out === "string" ? search.logged_out : undefined,
    return_to:
      typeof search.return_to === "string" ? search.return_to : undefined,
  }),
  component: LoginPage,
});

function LoginPage() {
  const { error, logged_out, return_to } = Route.useSearch();
  const [loading, setLoading] = useState(false);

  const handleContinue = async () => {
    setLoading(true);
    await initiateLogin(return_to);
  };

  return (
    <div className="mx-auto flex min-h-screen max-w-6xl font-outfit">
      <div className="flex flex-1 basis-1/2 flex-col pt-10 pl-14">
        <AnedotTypemarkIcon size={120} className="text-secondary-600" />
        <MarketingCarousel />
      </div>

      <div className="flex flex-1 basis-1/2 items-center justify-center overflow-auto px-6 py-10">
        <div className="w-full max-w-100">
          <div className="mb-8">
            <h1 className="mb-1.5 font-bold text-2xl text-foreground">
              Welcome back
            </h1>
            <p className="text-muted-foreground text-sm">
              Continue to the secure Anedot sign-in experience
            </p>
          </div>

          {error && (
            <div className="mb-4 rounded-md border border-destructive/20 bg-destructive/10 p-3 text-destructive text-sm">
              {error === "state_mismatch"
                ? "Invalid session state. Please try again."
                : error}
            </div>
          )}

          {logged_out && (
            <div className="mb-4 rounded-md border border-emerald-200 bg-emerald-50 p-3 text-emerald-700 text-sm">
              You have been signed out.
            </div>
          )}

          <div className="rounded-2xl border-2 border-border bg-card p-7 shadow-sm">
            <p className="text-muted-foreground text-sm leading-6">
              Sign-in, password recovery, multi-factor authentication, and
              account creation are all handled in the dedicated auth app.
            </p>

            <Button
              type="button"
              className="mt-6 h-10 w-full"
              onClick={handleContinue}
              disabled={loading}
            >
              {loading && <Loader2 className="animate-spin" size={16} />}
              {loading ? "Redirecting..." : "Continue to Sign In"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}
import type { AppBootstrap, Tenant, User } from "@/types/bootstrap";
