import { getMockApiUrls } from "./get-mock-api-urls";
import { expect, signedSessionCookie, test } from "./test-fixture";

const urls = getMockApiUrls();

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

test.describe("unauthenticated auth flow", () => {
  test.use({ authenticated: false });

  test("redirects missing authToken cookies to login with the original route", async ({
    page,
  }) => {
    await page.goto("/campaigns/101?tab=pages");

    await expect(page).toHaveURL(
      /\/login\?return_to=%2Fcampaigns%2F101%3Ftab%3Dpages/,
    );
  });

  test("builds an org-next authorize URL from the login page", async ({
    page,
  }) => {
    await page.route("http://localhost:3208/**", (route) =>
      route.fulfill({ status: 200, body: "auth app" }),
    );

    await page.goto("/login?return_to=/campaigns/101%3Ftab%3Dpages");

    const authRequest = page.waitForRequest((request) =>
      request.url().startsWith("http://localhost:3208/authorize"),
    );
    await page.getByRole("button", { name: /continue to sign in/i }).click();

    const authUrl = new URL((await authRequest).url());
    expect(authUrl.searchParams.get("app")).toBe("org-next");
    expect(authUrl.searchParams.get("return_to")).toBe(
      "/campaigns/101?tab=pages",
    );
    expect(authUrl.searchParams.get("state")).toMatch(
      /^[0-9a-f-]{36}$/i,
    );
    expect(authUrl.searchParams.has("client_id")).toBe(false);
    expect(authUrl.searchParams.has("session_url")).toBe(false);
  });

  test("rejects mismatched auth_state values", async ({ baseURL, context, page }) => {
    await context.addCookies([
      await signedSessionCookie(
        baseURL,
        "orgNextAuthTx",
        {
          returnTo: "/organizations/new",
          state: "expected-state",
        },
        600,
      ),
    ]);

    await page.goto("/organizations/new?auth_state=wrong-state");

    await expect(page).toHaveURL(/\/login\?error=state_mismatch/);
    await expect(page.getByText("Invalid session state.")).toBeVisible();
  });
});

test("verifies auth_state and removes it before loading the protected route", async ({
  baseURL,
  context,
  mockServerRequest,
  page,
}) => {
  await context.addCookies([
    await signedSessionCookie(
      baseURL,
      "orgNextAuthTx",
      {
        returnTo: "/organizations/new",
        state: "state-123",
      },
      600,
    ),
  ]);
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [] });

  await page.goto("/organizations/new?auth_state=state-123");

  await expect(page).toHaveURL(/\/organizations\/new$/);
});

