import { expect, test } from "@playwright/test";
import { fillInput, submitSignIn } from "./helpers";

async function mockOrgNextRedirect(page: Parameters<typeof submitSignIn>[0]) {
  await page.route("http://localhost:3210/**", (route) =>
    route.fulfill({ status: 200, body: "org-next" }),
  );
}

async function startOrgNextAuthorize(
  page: Parameters<typeof submitSignIn>[0],
  returnTo = "/campaigns?tab=pages",
  state = "state-123",
) {
  await mockOrgNextRedirect(page);
  const search = new URLSearchParams({
    app: "org-next",
    return_to: returnTo,
    state,
  });
  await page.goto(`/authorize?${search.toString()}`);
  await expect(page).toHaveURL(/\/sign-in/);
  await expect(page.getByRole("link", { name: /google/i })).toHaveCount(0);
}

async function expectOrgNextCookies(page: Parameters<typeof submitSignIn>[0]) {
  const cookies = await page.context().cookies("http://localhost:3210");
  const cookieNames = cookies.map((cookie) => cookie.name);

  expect(cookieNames).toContain("authToken");
  expect(cookieNames).toContain("refreshToken");
  expect(cookieNames).toContain("idToken");
}

async function expectOrgNextReturn(
  page: Parameters<typeof submitSignIn>[0],
  pathPattern = /localhost:3210\/campaigns\?tab=pages&auth_state=state-123/,
) {
  await expect(page).toHaveURL(pathPattern);
  await expectOrgNextCookies(page);
}

test("org-next password sign-in writes token cookies and redirects with auth_state", async ({
  page,
}) => {
  await startOrgNextAuthorize(page);

  await submitSignIn(page, "user@example.com");

  await expectOrgNextReturn(page);
});

test("org-next MFA challenge writes token cookies and redirects with auth_state", async ({
  page,
}) => {
  await startOrgNextAuthorize(page);

  await submitSignIn(page, "mfa@example.com");
  await expect(page).toHaveURL(/\/mfa-challenge/);
  await fillInput(page.getByLabel("Verification code"), "123456");
  await page.getByRole("button", { name: /verify/i }).click();

  await expectOrgNextReturn(page);
});

test("org-next new-password challenge writes token cookies and redirects with auth_state", async ({
  page,
}) => {
  await startOrgNextAuthorize(page);

  await submitSignIn(page, "newpass@example.com");
  await expect(page).toHaveURL(/\/force-change-password/);
  await fillInput(page.getByLabel("New password"), "NewPassword123!");
  await page.getByRole("button", { name: /set password/i }).click();

  await expectOrgNextReturn(page);
});

test("org-next sign-up confirmation signs in and writes token cookies", async ({
  page,
}) => {
  await startOrgNextAuthorize(page, "/welcome", "signup-state");

  await page.getByRole("link", { name: /sign up/i }).click();
  await expect(page).toHaveURL(/\/sign-up/);
  await expect(page.getByRole("link", { name: /google/i })).toHaveCount(0);
  await fillInput(page.getByLabel("First name"), "Test");
  await fillInput(page.getByLabel("Last name"), "User");
  await fillInput(page.getByLabel("Email address"), "newuser@example.com");
  await fillInput(page.getByLabel("Phone number"), "5555555555");
  await fillInput(page.getByLabel("Password", { exact: true }), "Password123!");
  await fillInput(page.getByLabel("Confirm password"), "Password123!");
  await page.getByRole("button", { name: /create account/i }).click();

  await expect(page).toHaveURL(/\/confirm-sign-up/);
  await fillInput(page.getByLabel("Verification code"), "123456");
  await page.getByRole("button", { name: /confirm account/i }).click();

  await expectOrgNextReturn(
    page,
    /localhost:3210\/welcome\?auth_state=signup-state/,
  );
});

test("org-next logout clears local token cookies even without Cognito revocation", async ({
  page,
}) => {
  await startOrgNextAuthorize(page);
  await submitSignIn(page, "user@example.com");
  await expectOrgNextReturn(page);

  await page.goto("/logout?app=org-next&return_to=/login%3Flogged_out%3D1");

  await expect(page).toHaveURL(/localhost:3210\/login\?logged_out=1/);
  const cookies = await page.context().cookies("http://localhost:3210");
  const cookieNames = cookies.map((cookie) => cookie.name);
  expect(cookieNames).not.toContain("authToken");
  expect(cookieNames).not.toContain("refreshToken");
  expect(cookieNames).not.toContain("idToken");
});

