import { env } from "@/env";
import {
  useAuthTokenSession,
  useAuthTransactionSession,
} from "@/server/session.server";
import { randomUUID } from "node:crypto";
import { redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";

function normalizeReturnTo(value: string | undefined): string {
  if (!value || !value.startsWith("/") || value.startsWith("//")) {
    return "/";
  }

  try {
    const parsed = new URL(value, "http://org-next.local");
    if (parsed.origin !== "http://org-next.local") {
      return "/";
    }
    return `${parsed.pathname}${parsed.search}${parsed.hash}`;
  } catch {
    return "/";
  }
}

export const redirectIfAuthenticated = createServerFn().handler(async () => {
  const session = await useAuthTokenSession();
  const hasAuthToken = !!session.data.authToken;

  if (hasAuthToken) {
    throw redirect({ to: "/" });
  }
});

export const startLogin = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      returnTo: z.string().optional(),
    }),
  )
  .handler(async ({ data }) => {
    const state = randomUUID();
    const returnTo = normalizeReturnTo(data.returnTo);
    const session = await useAuthTransactionSession();
    await session.update({ returnTo, state });

    const url = new URL("/authorize", env.VITE_AUTH_APP_URL);
    url.searchParams.set("app", "org-next");
    url.searchParams.set("return_to", returnTo);
    url.searchParams.set("state", state);
    return url.toString();
  });

export async function initiateLogin(returnTo?: string): Promise<void> {
  const url = await startLogin({ data: { returnTo } });
  window.location.assign(url);
}

export const verifyAuthReturn = createServerFn({ method: "GET" })
  .inputValidator(z.object({ href: z.string() }))
  .handler(async ({ data }) => {
    const url = new URL(data.href, "http://org-next.local");
    const authState = url.searchParams.get("auth_state");
    if (!authState) return;

    const session = await useAuthTransactionSession();
    if (session.data.state !== authState) {
      await session.clear();
      throw redirect({
        to: "/login",
        search: { error: "state_mismatch" },
      });
    }

    await session.clear();
    url.searchParams.delete("auth_state");
    const href = `${url.pathname}${url.search}${url.hash}`;
    throw redirect({ href });
  });

export async function performLogout(): Promise<void> {
  const url = new URL("/logout", env.VITE_AUTH_APP_URL);
  url.searchParams.set("app", "org-next");
  url.searchParams.set("return_to", "/login?logged_out=1");
  window.location.assign(url.toString());
}
