import { expect, test } from "@playwright/test";
import { fillInput, submitSignIn } from "./helpers";

async function mockOrgNextRedirect(page: Parameters<typeof submitSignIn>[0]) {
  await page.route("http://localhost:3210/**", (route) =>
    route.fulfill({ status: 200, body: "org-next" }),
  );
}

async function startOrgNextAuthorize(
  page: Parameters<typeof submitSignIn>[0],
  returnTo = "/campaigns?tab=pages",
  state = "state-123",
) {
  await mockOrgNextRedirect(page);
  const search = new URLSearchParams({
    app: "org-next",
    return_to: returnTo,
    state,
  });
  await page.goto(`/authorize?${search.toString()}`);
  await expect(page).toHaveURL(/\/sign-in/);
  await expect(page.getByRole("link", { name: /google/i })).toHaveCount(0);
}

async function expectOrgNextCookies(page: Parameters<typeof submitSignIn>[0]) {
  const cookies = await page.context().cookies("http://localhost:3210");
  const cookieNames = cookies.map((cookie) => cookie.name);

  expect(cookieNames).toContain("authToken");
  expect(cookieNames).toContain("refreshToken");
  expect(cookieNames).toContain("idToken");
}

async function expectOrgNextReturn(
  page: Parameters<typeof submitSignIn>[0],
  pathPattern = /localhost:3210\/campaigns\?tab=pages&auth_state=state-123/,
) {
  await expect(page).toHaveURL(pathPattern);
  await expectOrgNextCookies(page);
}

test("org-next password sign-in writes token cookies and redirects with auth_state", async ({
  page,
}) => {
  await startOrgNextAuthorize(page);

  await submitSignIn(page, "user@example.com");

  await expectOrgNextReturn(page);
});

