  if (!authResult?.AccessToken || !authResult?.IdToken) return null;

  const claims = decodeIdTokenClaims(authResult.IdToken);
  const refreshToken = authResult.RefreshToken ?? fallbackRefreshToken;
  const [authTokenSession, refreshTokenSession, idTokenSession] =
    await Promise.all([
      useOrgNextAuthTokenSession(),
      useOrgNextRefreshTokenSession(),
      useOrgNextIdTokenSession(),
    ]);

  await Promise.all([
    authTokenSession.update({ authToken: authResult.AccessToken }),
    refreshToken
      ? refreshTokenSession.update({
          refreshToken,
          username: claims.email,
        })
      : Promise.resolve(),
    idTokenSession.update({ idToken: authResult.IdToken }),
  ]);

  return claims;
}

